// ── VERSION ──
const SITE_VERSION = 'v1.5';
const SITE_DATE = '2026-04-30';

// ── Show version in footer ──
document.addEventListener('DOMContentLoaded', () => {
  const vEl = document.getElementById('site-version');
  if(vEl) vEl.textContent = `${SITE_VERSION} · ${SITE_DATE}`;
});

// Scroll to top visibility
const scrollTopBtn = document.getElementById('scroll-top');
window.addEventListener('scroll', () => {
  if(window.scrollY > 400){
    scrollTopBtn.style.opacity='1';
    scrollTopBtn.style.pointerEvents='auto';
  } else {
    scrollTopBtn.style.opacity='0';
    scrollTopBtn.style.pointerEvents='none';
  }
});

// Scroll reveal
const reveals = document.querySelectorAll('.reveal');
const observer = new IntersectionObserver(entries => {
  entries.forEach((entry, i) => {
    if (entry.isIntersecting) {
      setTimeout(() => entry.target.classList.add('visible'), i * 80);
    }
  });
}, { threshold: 0.1 });
reveals.forEach(r => observer.observe(r));

// Nav scroll effect
window.addEventListener('scroll', () => {
  const nav = document.getElementById('navbar');
  nav.style.background = window.scrollY > 50
    ? 'rgba(0,0,0,0.95)'
    : 'rgba(0,0,0,0.8)';
});

function showMatInfo(key) {
  const m = MAT_DATA[key]; if(!m) return;
  document.querySelectorAll('#mat-chips .chip').forEach(c => c.classList.remove('highlight'));
  event.target.classList.add('highlight');
  const specsHtml = (m.specs||[]).map(([label,val])=>`
    <div style="background:rgba(0,0,0,0.3);border-radius:6px;padding:8px 10px">
      <div style="font-size:9px;color:rgba(255,255,255,0.4);letter-spacing:1.5px;text-transform:uppercase;margin-bottom:3px;font-family:monospace">${label}</div>
      <div style="font-size:13px;font-weight:700;color:#fff;font-family:monospace">${val}</div>
    </div>`).join('');
  document.getElementById('mat-info-content').innerHTML = `
    <div style="font-weight:700;color:#fff;font-size:14px;margin-bottom:10px;display:flex;align-items:center;gap:8px;flex-wrap:wrap">
      <span style="width:10px;height:10px;border-radius:50%;background:${m.color};flex-shrink:0;display:inline-block;border:1px solid rgba(255,255,255,0.2)"></span>
      ${m.name||m.nombre}
    </div>
    <p style="margin-bottom:12px;color:rgba(255,255,255,0.75);font-size:12px;line-height:1.6">${m.desc}</p>
    <div style="display:grid;grid-template-columns:repeat(auto-fill,minmax(140px,1fr));gap:6px;margin-bottom:10px">${specsHtml}</div>
    <div style="font-size:11px;color:rgba(255,255,255,0.5);font-family:monospace">📌 ${m.usos}</div>`;
}

