// ── Galería rotativa RC 1:10 ──
const RC_IMGS = [
  'data:image/png;base64,',
  'data:image/png;base64,',
  'data:image/png;base64,'
];
let _rcIdx = 0;
let _rcTimer = null;

function setRCImg(idx, dotEl) {
  _rcIdx = idx;
  const imgEl = document.getElementById('rc-img');
  if (imgEl) {
    imgEl.style.opacity = '0';
    setTimeout(() => {
      imgEl.src = RC_IMGS[idx];
      imgEl.style.opacity = '1';
    }, 250);
  }
  document.querySelectorAll('.rc-dot').forEach((d,i) => {
    d.style.transform = i === idx ? 'scale(1.4)' : 'scale(1)';
    d.classList.toggle('active', i === idx);
  });
}

function startRCRotation() {
  _rcTimer = setInterval(() => {
    setRCImg((_rcIdx + 1) % RC_IMGS.length, null);
  }, 2000);
}

function stopRCRotation() {
  clearInterval(_rcTimer);
  setRCImg(0, null);
}

