// ── Alias openCotizar → openCotizarModal (todos los botones del sitio usan este nombre) ──
function openCotizar() { openCotizarModal(); }

// ── Estado del descuento primer pedido ──
let _cotDescuento = false; // true si el usuario califica

async function checkPrimerPedido() {
  // Sin usuario logueado → no aplica descuento
  if (!currentPortalUser) return false;
  // Con usuario logueado → verificar si tiene compras o pedidos previos en Firebase
  if (!firebaseDB) return false;
  try {
    const uid = currentPortalUser.uid;
    const snap = await firebaseDB.ref(`marcanotech-dashboard/clientes-portal/${uid}`).once('value');
    const data = snap.val() || {};
    const tieneCompras  = data.compras  && Object.keys(data.compras).length  > 0;
    const tienePedidos  = data.pedidos  && Object.keys(data.pedidos).length  > 0;
    // Califica si NO tiene ni compras ni pedidos previos
    return !tieneCompras && !tienePedidos;
  } catch(e) {
    return false;
  }
}

function renderCotBanner() {
  const bannerEl  = document.getElementById('cot-descuento-banner');
  const loginEl   = document.getElementById('cot-login-prompt');
  const submitLbl = document.getElementById('cot-submit-label');
  if (!bannerEl || !loginEl) return;

  if (currentPortalUser && _cotDescuento) {
    bannerEl.style.display = 'flex';
    loginEl.style.display  = 'none';
    document.getElementById('cot-descuento-nombre').textContent =
      (currentPortalUser.displayName || currentPortalUser.email).split(' ')[0];
    if (submitLbl) submitLbl.textContent = 'Enviar con 10% OFF — WhatsApp';
  } else if (currentPortalUser && !_cotDescuento) {
    bannerEl.style.display = 'none';
    loginEl.style.display  = 'none';
    if (submitLbl) submitLbl.textContent = 'Publicar solicitud por WhatsApp';
  } else {
    bannerEl.style.display = 'none';
    loginEl.style.display  = 'flex';
    if (submitLbl) submitLbl.textContent = 'Publicar solicitud por WhatsApp';
  }
}

async function openCotizarModal() {
  const m = document.getElementById('cotizar-modal');
  m.style.display = 'flex';
  m.onclick = e => { if (e.target === m) closeCotizarModal(); };
  document.body.style.overflow = 'hidden';

  // Precompletar contacto si el usuario está logueado
  if (currentPortalUser) {
    const waInput    = document.getElementById('cot-wa');
    const emailInput = document.getElementById('cot-email');
    if (emailInput && !emailInput.value) emailInput.value = currentPortalUser.email || '';
    // Intentar precargar teléfono desde Firebase
    if (firebaseDB) {
      firebaseDB.ref(`marcanotech-dashboard/clientes-portal/${currentPortalUser.uid}/perfil`)
        .once('value').then(snap => {
          const p = snap.val() || {};
          if (waInput && !waInput.value && p.telefono) waInput.value = p.telefono;
        }).catch(()=>{});
    }
    // Verificar si califica al descuento
    _cotDescuento = await checkPrimerPedido();
  } else {
    _cotDescuento = false;
  }
  renderCotBanner();
}

function closeCotizarModal() {
  document.getElementById('cotizar-modal').style.display = 'none';
  document.body.style.overflow = '';
  _cotDescuento = false;
}

function submitCotizacion(e) {
  if (e) e.preventDefault();
  const titulo = document.getElementById('cot-titulo').value.trim();
  const desc   = document.getElementById('cot-desc').value.trim();
  if (!titulo || !desc) { alert('Completá el título y la descripción para continuar.'); return; }
  const ciudad = document.getElementById('cot-ciudad').value.trim();
  const prov   = document.getElementById('cot-prov').value.trim();
  const wa     = document.getElementById('cot-wa').value.trim();
  const email  = document.getElementById('cot-email').value.trim();

  // Línea de descuento si aplica
  const descuentoLinea = _cotDescuento && currentPortalUser
    ? `\n\n🎁 *DESCUENTO PRIMER PEDIDO — 10% OFF*\nCliente registrado: ${currentPortalUser.email}`
    : '';

  const msg = `🖨️ *Nueva Cotización — MarcanoTech*\n\n*${titulo}*\n\n${desc}${descuentoLinea}${ciudad||prov?'\n\n📍 '+[ciudad,prov].filter(Boolean).join(', '):''}${wa?'\n📱 '+wa:''}${email?'\n✉️ '+email:''}`;
  window.open(`https://wa.me/5491123468533?text=${encodeURIComponent(msg)}`, '_blank');

  // Registrar el pedido en Firebase para que no vuelva a calificar
  if (_cotDescuento && currentPortalUser && firebaseDB) {
    const uid = currentPortalUser.uid;
    const key = Date.now().toString(36);
    firebaseDB.ref(`marcanotech-dashboard/clientes-portal/${uid}/pedidos/${key}`).set({
      descripcion: titulo,
      estado:      'Pendiente',
      fecha:       new Date().toISOString(),
      descuento:   '10%',
      origen:      'web-primer-pedido'
    }).catch(() => {});
  }

  closeCotizarModal();
}


function toggleMenu() {
  document.getElementById('mobile-menu').classList.toggle('open');
  document.body.style.overflow =
    document.getElementById('mobile-menu').classList.contains('open') ? 'hidden' : '';
}

