// Estado de filtros activos
let _cfMarca = '';
let _cfDispo = '';
let _catalogoColores = [...COLORES_BASE];

// ── Renderizar grilla ──
function renderColoresGrid() {
  const grid = document.getElementById('colores-grid');
  if (!grid) return;

  const filtrados = _catalogoColores.filter(c => {
    const okMarca = !_cfMarca || c.marca === _cfMarca;
    const okDispo = !_cfDispo || c.dispo === _cfDispo;
    return okMarca && okDispo;
  });

  if (!filtrados.length) {
    grid.innerHTML = `<div style="grid-column:1/-1;text-align:center;padding:40px;color:rgba(255,255,255,0.25);font-size:13px">No hay colores con ese filtro.</div>`;
    return;
  }

  const dispoColor = { stock:'#34d399', disponible:'#fbbf24', consultar:'#9eaab8' };
  const dispoLabel = { stock:'En stock', disponible:'Disponible', consultar:'Bajo pedido' };

  // Determinar si el color del swatch necesita texto oscuro
  function needsDark(hex) {
    const r = parseInt(hex.slice(1,3),16);
    const g = parseInt(hex.slice(3,5),16);
    const b = parseInt(hex.slice(5,7),16);
    return (r*0.299 + g*0.587 + b*0.114) > 160;
  }

  grid.innerHTML = filtrados.map(c => {
    const dc = dispoColor[c.dispo] || '#9eaab8';
    const dl = dispoLabel[c.dispo] || c.dispo;
    const dark = needsDark(c.hex);
    return `
    <div class="color-card" title="${c.nombre} · ${c.marca} · ${c.material} · ${dl}">
      <div class="color-card-swatch" style="background:${c.hex}">
        <div class="color-card-dispo" style="background:${dc}"></div>
      </div>
      <div class="color-card-body">
        <div class="color-card-name">${c.nombre}</div>
        <div class="color-card-meta">
          <span>${c.marca}</span>
          <span>${c.hex.toUpperCase()}</span>
        </div>
        <span class="color-card-mat">${c.material}</span>
      </div>
    </div>`;
  }).join('');
}

// ── Filtrar ──
function filtrarColores(tipo, valor, btn) {
  if (tipo === 'marca') {
    _cfMarca = valor;
    document.querySelectorAll('.cf-btn').forEach(b => b.classList.remove('active'));
  } else {
    _cfDispo = valor;
    document.querySelectorAll('.cf-btn-dispo').forEach(b => b.classList.remove('active'));
  }
  btn.classList.add('active');
  renderColoresGrid();
}

// ── Fusionar con Firebase si hay colores extras ──
function loadCatalogoFromFirebase() {
  if (typeof firebase === 'undefined' || !firebase.apps.length) {
    renderColoresGrid();
    return;
  }
  try {
    firebase.database().ref('marcanotech-dashboard/catalogo-colores').once('value')
      .then(snap => {
        const data = snap.val();
        if (data) {
          const extras = Object.values(data);
          // Fusionar: los de Firebase sobreescriben los base si tienen el mismo id
          const baseIds = new Set(COLORES_BASE.map(c => c.id));
          const nuevos  = extras.filter(c => !baseIds.has(c.id));
          // Actualizar estado de los base si Firebase tiene una versión más nueva
          const firebaseMap = {};
          extras.forEach(c => { firebaseMap[c.id] = c; });
          _catalogoColores = COLORES_BASE.map(c => firebaseMap[c.id] || c).concat(nuevos);
        }
        renderColoresGrid();
      })
      .catch(() => renderColoresGrid());
  } catch(e) {
    renderColoresGrid();
  }
}

// ── Inicializar cuando el DOM esté listo ──
document.addEventListener('DOMContentLoaded', () => {
  // Renderizar con los datos base inmediatamente
  renderColoresGrid();
  // Intentar enriquecer desde Firebase en background
  (function waitFirebaseColores() {
    if (typeof firebase !== 'undefined') {
      loadCatalogoFromFirebase();
    } else {
      setTimeout(waitFirebaseColores, 300);
    }
  })();
});



// ── Firebase config (mismo proyecto del dashboard) ──
const firebaseConfigWeb = {
  apiKey: "AIzaSyAfsAEiXCL5aSUtWsBrc3DaIYLlagU2Q6s",
  authDomain: "marcanotech-3d.firebaseapp.com",
  databaseURL: "https://marcanotech-3d-default-rtdb.firebaseio.com",
  projectId: "marcanotech-3d",
  storageBucket: "marcanotech-3d.appspot.com",
  messagingSenderId: "95407454758",
  appId: "1:95407454758:web:092246282f460f3b5e44e7"
};

let firebaseApp = null;
let firebaseAuth = null;
let firebaseDB = null;
let currentPortalUser = null;

// ── Inicializar Firebase cuando el SDK cargue ──
function initFirebasePortal() {
  if (typeof firebase === 'undefined') return;
  if (firebaseApp) return;
  try {
    // Reusar app si ya existe (dashboard puede haberla inicializado)
    firebaseApp = firebase.apps.length
      ? firebase.app()
      : firebase.initializeApp(firebaseConfigWeb);
    firebaseAuth = firebase.auth();
    firebaseDB   = firebase.database();

    firebaseAuth.onAuthStateChanged(user => {
      if (user) {
        currentPortalUser = user;
        onUserLoggedIn(user);
      } else {
        currentPortalUser = null;
        onUserLoggedOut();
      }
    });
  } catch(e) {
    console.warn('Firebase portal init error:', e);
  }
}

// ── Estado de auth → UI ──
function onUserLoggedIn(user) {
  // Nav button → nombre + avatar
  const btn    = document.getElementById('nav-auth-btn');
  const label  = document.getElementById('nav-auth-label');
  const avatar = document.getElementById('nav-auth-avatar');
  const icon   = btn.querySelector('svg');

  const name = user.displayName || user.email.split('@')[0];
  label.textContent = name.split(' ')[0];
  avatar.style.display = 'flex';
  if(user.photoURL) {
    avatar.innerHTML = `<img src="${user.photoURL}" alt="">`;
  } else {
    avatar.textContent = name[0].toUpperCase();
  }
  if(icon) icon.style.display = 'none';

  // Mobile link
  const mobileLink = document.getElementById('mobile-auth-link');
  if(mobileLink) mobileLink.textContent = 'Mi Portal';

  closeAuthModal();
  loadPortalData(user);
}

function onUserLoggedOut() {
  const btn    = document.getElementById('nav-auth-btn');
  const label  = document.getElementById('nav-auth-label');
  const avatar = document.getElementById('nav-auth-avatar');
  const icon   = btn.querySelector('svg');

  label.textContent = 'Mi Cuenta';
  avatar.style.display = 'none';
  if(icon) icon.style.display = '';

  const mobileLink = document.getElementById('mobile-auth-link');
  if(mobileLink) mobileLink.textContent = 'Mi Cuenta';

  hidePortal();
}

// ── Click en botón nav ──
function handleNavAuthClick() {
  if (currentPortalUser) {
    showPortal();
  } else {
    openAuthModal();
  }
}

// ── Modal Auth ──
function openAuthModal() {
  document.getElementById('auth-modal-overlay').classList.add('open');
  document.body.style.overflow = 'hidden';
  clearAuthError();
}
function closeAuthModal() {
  document.getElementById('auth-modal-overlay').classList.remove('open');
  document.body.style.overflow = '';
}

function switchAuthTab(tab) {
  document.getElementById('tab-login').classList.toggle('active', tab === 'login');
  document.getElementById('tab-register').classList.toggle('active', tab === 'register');
  document.getElementById('auth-form-login').style.display    = tab === 'login'    ? 'block' : 'none';
  document.getElementById('auth-form-register').style.display = tab === 'register' ? 'block' : 'none';
  clearAuthError();
}

function showAuthError(msg) {
  const el = document.getElementById('auth-error');
  el.textContent = msg;
  el.classList.add('visible');
}
function clearAuthError() {
  document.getElementById('auth-error').classList.remove('visible');
}

const _eyeOn  = `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></svg>`;
const _eyeOff = `<svg width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24"/><line x1="1" y1="1" x2="23" y2="23"/></svg>`;
function togglePwd(id, btn) {
  const input = document.getElementById(id);
  const show  = input.type === 'password';
  input.type  = show ? 'text' : 'password';
  btn.innerHTML = show ? _eyeOff : _eyeOn;
}

// ── Google OAuth ──
function signInWithGoogle() {
  if (!firebaseAuth) { showAuthError('Firebase no disponible.'); return; }
  const provider = new firebase.auth.GoogleAuthProvider();
  firebaseAuth.signInWithPopup(provider)
    .then(result => {
      return ensurePortalProfile(result.user)
        .then(() => { if (currentPortalUser) loadPortalData(result.user); });
    })
    .catch(err => {
      showAuthError(translateAuthError(err.code));
    });
}

// ── Email + Password ──
function signInWithEmail() {
  if (!firebaseAuth) { showAuthError('Firebase no disponible.'); return; }
  const email = document.getElementById('login-email').value.trim();
  const pass  = document.getElementById('login-password').value;
  if(!email || !pass) { showAuthError('Completá email y contraseña.'); return; }
  clearAuthError();
  firebaseAuth.signInWithEmailAndPassword(email, pass)
    .catch(err => showAuthError(translateAuthError(err.code)));
}

function registerWithEmail() {
  if (!firebaseAuth) { showAuthError('Firebase no disponible.'); return; }
  const name  = document.getElementById('reg-name').value.trim();
  const email = document.getElementById('reg-email').value.trim();
  const pass  = document.getElementById('reg-password').value;
  const phone = document.getElementById('reg-phone').value.trim();
  if(!name || !email || !pass) { showAuthError('Completá nombre, email y contraseña.'); return; }
  if(pass.length < 6) { showAuthError('La contraseña debe tener al menos 6 caracteres.'); return; }
  const confirm = document.getElementById('reg-password-confirm').value;
  if(pass !== confirm) { showAuthError('Las contraseñas no coinciden.'); return; }
  clearAuthError();
  firebaseAuth.createUserWithEmailAndPassword(email, pass)
    .then(result => {
      return result.user.updateProfile({ displayName: name })
        .then(() => ensurePortalProfile(result.user, { nombre: name, telefono: phone }))
        .then(() => onUserLoggedIn(result.user));
    })
    .catch(err => showAuthError(translateAuthError(err.code)));
}

function sendPasswordReset() {
  if (!firebaseAuth) { showAuthError('Firebase no disponible.'); return; }
  const email = document.getElementById('login-email').value.trim();
  if(!email) { showAuthError('Ingresá tu email primero.'); return; }
  firebaseAuth.sendPasswordResetEmail(email)
    .then(() => showAuthError('✅ Revisá tu email para restablecer la contraseña.'))
    .catch(err => showAuthError(translateAuthError(err.code)));
}

function signOutUser() {
  if (!firebaseAuth) return;
  firebaseAuth.signOut().then(() => {
    hidePortal();
    // Scroll a inicio
    window.scrollTo({ top: 0, behavior: 'smooth' });
  });
}

// ── Crear / asegurar perfil en RTDB ──
function ensurePortalProfile(user, extra = {}) {
  if (!firebaseDB) return Promise.resolve();
  const ref = firebaseDB.ref(`marcanotech-dashboard/clientes-portal/${user.uid}/perfil`);
  return ref.once('value').then(snap => {
    if (!snap.exists()) {
      return ref.set({
        nombre:    extra.nombre   || user.displayName || '',
        email:     user.email     || '',
        telefono:  extra.telefono || '',
        fotoURL:   user.photoURL  || '',
        tier:      'standard',
        creadoEn:  new Date().toISOString(),
        uid:       user.uid
      });
    }
  });
}

// ── Cargar datos del portal ──
function loadPortalData(user) {
  if (!firebaseDB) {
    renderPortalOffline(user);
    return;
  }
  const portalRef = firebaseDB.ref(`marcanotech-dashboard/clientes-portal/${user.uid}`);
  portalRef.once('value').then(snap => {
    const data = snap.val() || {};
    renderPortal(user, data);
  }).catch(() => renderPortalOffline(user));
}

function renderPortal(user, data) {
  const perfil = data.perfil || {};
  const nombre = perfil.nombre || user.displayName || user.email.split('@')[0];
  const tier   = perfil.tier || 'standard';
  const isVip  = tier === 'vip';

  // Header
  document.getElementById('portal-username').textContent = nombre.toUpperCase();
  document.getElementById('portal-email-display').textContent = user.email;
  document.getElementById('portal-badge-vip').style.display  = isVip  ? 'inline' : 'none';
  document.getElementById('portal-badge-std').style.display  = !isVip ? 'inline' : 'none';

  // Perfil card
  const avatarEl = document.getElementById('portal-profile-avatar');
  avatarEl.textContent = '';
  if (user.photoURL) {
    avatarEl.innerHTML = `<img src="${user.photoURL}" alt="">`;
  } else {
    avatarEl.textContent = nombre[0].toUpperCase();
  }
  document.getElementById('portal-profile-name').textContent  = nombre;
  document.getElementById('portal-profile-email').textContent = user.email;
  document.getElementById('portal-phone-display').textContent = perfil.telefono || 'No registrado';
  document.getElementById('portal-tier-display').textContent  = isVip ? '★ VIP' : 'Estándar';

  // Fecha de ingreso
  if (perfil.creadoEn) {
    const d = new Date(perfil.creadoEn);
    document.getElementById('portal-member-since').textContent =
      d.toLocaleDateString('es-AR', { year:'numeric', month:'long', day:'numeric' });
  }

  // VIP card
  document.getElementById('portal-vip-card').style.display = isVip ? 'block' : 'none';
  if (isVip && perfil.descuento) {
    document.getElementById('portal-vip-discount').textContent = perfil.descuento + '%';
  }

  // Pedidos
  renderPedidos(data.pedidos);

  // Compras
  renderCompras(data.compras);

  // Proyectos
  renderProyectos(data.proyectos);

  showPortal();
}

function renderPortalOffline(user) {
  const nombre = user.displayName || user.email.split('@')[0];
  document.getElementById('portal-username').textContent = nombre.toUpperCase();
  document.getElementById('portal-email-display').textContent = user.email;
  document.getElementById('portal-profile-name').textContent  = nombre;
  document.getElementById('portal-profile-email').textContent = user.email;
  document.getElementById('portal-member-since').textContent  = '—';
  document.getElementById('portal-phone-display').textContent = '—';
  renderPedidos(null);
  renderCompras(null);
  renderProyectos(null);
  showPortal();
}

// ── Renderers ──
function renderPedidos(pedidos) {
  const list = document.getElementById('portal-pedidos-list');
  const count = document.getElementById('portal-pedidos-count');
  if (!pedidos) {
    count.textContent = '0 pedidos';
    list.innerHTML = `<div class="portal-empty"><div class="portal-empty-icon">📭</div>No tenés pedidos aún.<br><small style="color:#404050">Tus cotizaciones aparecerán aquí una vez procesadas.</small></div>`;
    return;
  }
  const arr = Object.values(pedidos).sort((a,b) => new Date(b.fecha||0) - new Date(a.fecha||0));
  count.textContent = arr.length + (arr.length === 1 ? ' pedido' : ' pedidos');
  list.innerHTML = arr.map(p => `
    <div class="portal-list-item">
      <div class="portal-item-title">${escHtml(p.titulo || p.descripcion || 'Pedido')}</div>
      <div class="portal-item-meta">
        <span>${formatDateShort(p.fecha)}</span>
        <span class="portal-status ${(p.estado||'pendiente').toLowerCase().replace(' ','-')}">${p.estado || 'Pendiente'}</span>
        ${p.total ? `<span>$${p.total}</span>` : ''}
      </div>
    </div>`).join('');
}

function renderCompras(compras) {
  const list  = document.getElementById('portal-compras-list');
  const count = document.getElementById('portal-compras-count');
  if (!compras) {
    count.textContent = '0 compras';
    list.innerHTML = `<div class="portal-empty"><div class="portal-empty-icon">🛒</div>Sin historial de compras aún.</div>`;
    return;
  }
  const arr = Object.values(compras).sort((a,b) => new Date(b.fecha||0) - new Date(a.fecha||0));
  count.textContent = arr.length + (arr.length === 1 ? ' compra' : ' compras');
  list.innerHTML = arr.map(c => `
    <div class="portal-list-item">
      <div class="portal-item-title">${escHtml(c.descripcion || c.titulo || 'Compra')}</div>
      <div class="portal-item-meta">
        <span>${formatDateShort(c.fecha)}</span>
        ${c.monto ? `<span style="color:#34d399;font-weight:700">$${c.monto}</span>` : ''}
        <span class="portal-status completado">Completado</span>
      </div>
    </div>`).join('');
}

function renderProyectos(proyectos) {
  const list  = document.getElementById('portal-proyectos-list');
  const count = document.getElementById('portal-proyectos-count');
  if (!proyectos) {
    count.textContent = '0 proyectos';
    list.innerHTML = `<div class="portal-empty"><div class="portal-empty-icon">✏️</div>No tenés proyectos personalizados.<br><small style="color:#404050">Podés solicitar uno desde el botón de cotización.</small></div>`;
    return;
  }
  const arr = Object.values(proyectos).sort((a,b) => new Date(b.fecha||0) - new Date(a.fecha||0));
  count.textContent = arr.length + (arr.length === 1 ? ' proyecto' : ' proyectos');
  list.innerHTML = arr.map(p => `
    <div class="portal-list-item">
      <div class="portal-item-title">${escHtml(p.nombre || p.titulo || 'Proyecto')}</div>
      <div class="portal-item-meta">
        <span>${formatDateShort(p.fecha)}</span>
        <span class="portal-status ${getStatusClass(p.estado)}">${p.estado || 'Pendiente'}</span>
        ${p.progreso ? `<span>${p.progreso}%</span>` : ''}
      </div>
      ${p.nota ? `<div style="font-size:11px;color:#505060;margin-top:5px;font-style:italic">${escHtml(p.nota)}</div>` : ''}
    </div>`).join('');
}

// ── Mostrar / ocultar portal ──
function showPortal() {
  document.getElementById('portal-cliente').classList.add('visible');
  // Ocultar secciones del sitio principal
  document.querySelectorAll('section:not(#portal-cliente)').forEach(s => s.style.display = 'none');
  // Ocultar footer si existe
  const footer = document.querySelector('footer');
  if(footer) footer.style.display = 'none';
  // Scroll top
  window.scrollTo({ top: 0, behavior: 'smooth' });
}

function hidePortal() {
  document.getElementById('portal-cliente').classList.remove('visible');
  document.querySelectorAll('section:not(#portal-cliente)').forEach(s => s.style.display = '');
  const footer = document.querySelector('footer');
  if(footer) footer.style.display = '';
}

function closePortal() {
  hidePortal();
}

// ── Helpers ──
function escHtml(str) {
  return String(str||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
}
function formatDateShort(iso) {
  if(!iso) return '—';
  try {
    const d = new Date(iso);
    return d.toLocaleDateString('es-AR', { day:'2-digit', month:'short', year:'numeric' });
  } catch { return iso; }
}
function getStatusClass(estado) {
  const s = (estado||'').toLowerCase();
  if(s.includes('complet') || s.includes('entregad')) return 'completado';
  if(s.includes('proces') || s.includes('imprimiendo') || s.includes('diseño')) return 'en-proceso';
  if(s.includes('cancel')) return 'cancelado';
  return 'pendiente';
}
function translateAuthError(code) {
  const map = {
    'auth/invalid-email':            'El email no es válido.',
    'auth/user-not-found':           'No existe una cuenta con ese email.',
    'auth/wrong-password':           'Contraseña incorrecta.',
    'auth/email-already-in-use':     'Ese email ya está registrado.',
    'auth/weak-password':            'La contraseña es muy débil (mínimo 6 caracteres).',
    'auth/too-many-requests':        'Demasiados intentos. Esperá unos minutos.',
    'auth/popup-closed-by-user':     'Cerraste el popup de Google antes de completar.',
    'auth/network-request-failed':   'Error de conexión. Revisá tu internet.',
    'auth/invalid-credential':       'Credenciales inválidas. Verificá tu email y contraseña.',
  };
  return map[code] || `Error: ${code}`;
}

// ── Cerrar modal al hacer click fuera ──
document.addEventListener('DOMContentLoaded', () => {
  document.getElementById('auth-modal-overlay').addEventListener('click', function(e) {
    if(e.target === this) closeAuthModal();
  });

  document.querySelectorAll('a[href^="#"]').forEach(a => {
    const hash = a.getAttribute('href');
    if(hash === '#' || !hash) return;
    a.addEventListener('click', function() {
      if(document.getElementById('portal-cliente').classList.contains('visible')) {
        closePortal();
        setTimeout(() => {
          const target = document.querySelector(hash);
          if(target) target.scrollIntoView({ behavior: 'smooth' });
        }, 50);
      }
    });
  });
});

// ── Inicializar Firebase ──
// El SDK se carga desde el <head> — esperamos que esté disponible
(function waitForFirebase() {
  if (typeof firebase !== 'undefined') {
    initFirebasePortal();
  } else {
    setTimeout(waitForFirebase, 100);
  }
})();

